skySphere.vertexProgram:
void main(void)
{
    gl_TexCoord[0] = gl_MultiTexCoord0;
    gl_Position     = ftransform();
    gl_ClipVertex = gl_ModelViewMatrix*gl_Vertex;
}

skySphere.fragmentProgram:
uniform sampler2D tex1;
uniform float top; 
uniform float bottom; 
uniform vec4 floorColor;

float rand(vec2 co){
    return fract(sin(dot(co, vec2(12.9898, 78.233))) * 43758.5453);
}

void main (void)
{ 
    vec2 texcoord = gl_TexCoord[0].xy;
    vec4 texColor  = texture2D(tex1, texcoord);
    /*vec4 floorColor = 
        texture2D(tex1, vec2(0.0, 0.0)) +
        texture2D(tex1, vec2(0.2, 0.0)) +
        texture2D(tex1, vec2(0.4, 0.0)) +
        texture2D(tex1, vec2(0.6, 0.0)) +
        texture2D(tex1, vec2(0.8, 0.0)) +
        texture2D(tex1, vec2(1.0, 0.0));

    floorColor /= 6.0;*/

    gl_FragColor = mix(
        mix(floorColor * 0.5, floorColor, smoothstep(0.0, 0.44, texcoord.y + rand(texcoord)*0.01)),
            texColor, smoothstep(bottom, top, texcoord.y));
}
